import{_ as t,c as a,S as s,o as l}from"./chunks/framework.BjmDYXuv.js";const g=JSON.parse('{"title":"Model Zoo","description":"","frontmatter":{},"headers":[],"relativePath":"spaces/model-zoo.md","filePath":"spaces/model-zoo.md","lastUpdated":1776176868000}'),i={name:"spaces/model-zoo.md"};function o(n,e,d,r,c,h){return l(),a("div",null,e[0]||(e[0]=[s(`<h1 id="model-zoo" tabindex="-1">Model Zoo <a class="header-anchor" href="#model-zoo" aria-label="Permalink to &quot;Model Zoo&quot;">​</a></h1><p><strong>Live:</strong> <a href="https://huggingface.co/spaces/CERN/colliderml-model-zoo" target="_blank" rel="noreferrer">huggingface.co/spaces/CERN/colliderml-model-zoo</a><strong>Source:</strong> <a href="https://github.com/OpenDataDetector/ColliderML/tree/main/spaces/model-zoo" target="_blank" rel="noreferrer"><code>spaces/model-zoo/</code></a></p><p>A browser for HuggingFace models tagged <code>colliderml</code>. Discovery is entirely tag-based: the Space calls <code>huggingface_hub.list_models(filter=&quot;colliderml&quot;, limit=500, full=True)</code> and lays the results out in a sortable table.</p><h2 id="getting-your-model-listed" tabindex="-1">Getting your model listed <a class="header-anchor" href="#getting-your-model-listed" aria-label="Permalink to &quot;Getting your model listed&quot;">​</a></h2><p>Add the <code>colliderml</code> tag to your model card and (optionally) an appropriate task tag:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tags</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">- </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">colliderml</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">- </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">tracking</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # or jets, anomaly, or omit for &quot;general&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">task_category</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">object-detection</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span></code></pre></div><p>Re-push the model — the Space picks up the new tag on its next refresh (tag queries go through HuggingFace&#39;s live API; no re-deploy needed).</p><h2 id="columns" tabindex="-1">Columns <a class="header-anchor" href="#columns" aria-label="Permalink to &quot;Columns&quot;">​</a></h2><table><thead><tr><th style="text-align:left;">Column</th><th style="text-align:left;">Source</th></tr></thead><tbody><tr><td style="text-align:left;"><code>model</code></td><td style="text-align:left;"><code>m.modelId</code> (repo name)</td></tr><tr><td style="text-align:left;"><code>task</code></td><td style="text-align:left;">First of <code>tracking</code> / <code>jets</code> / <code>anomaly</code> in the tag list, else <code>general</code></td></tr><tr><td style="text-align:left;"><code>downloads</code></td><td style="text-align:left;">HuggingFace download count</td></tr><tr><td style="text-align:left;"><code>likes</code></td><td style="text-align:left;">HuggingFace like count</td></tr><tr><td style="text-align:left;"><code>pipeline</code></td><td style="text-align:left;"><code>m.pipeline_tag</code></td></tr><tr><td style="text-align:left;"><code>url</code></td><td style="text-align:left;">Direct link to the model card</td></tr></tbody></table><p>The default sort is by download count, descending. The <strong>Filter by task</strong> dropdown lets you narrow to one of the three physics tasks or to <code>general</code> (everything else).</p><h2 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h2><p>Public models only — no HuggingFace sign-in needed.</p><h2 id="running-it-locally" tabindex="-1">Running it locally <a class="header-anchor" href="#running-it-locally" aria-label="Permalink to &quot;Running it locally&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> spaces/model-zoo</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install -r requirements.txt</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.py</span></span></code></pre></div><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><ul><li>The Space caps the query at 500 models per refresh. If you have more than 500 models tagged <code>colliderml</code> (a nice problem to have), bump the <code>limit=</code> argument in <code>fetch_models()</code>.</li><li>Task detection is naïve — it looks for a literal tag match. If you use different tags (e.g. <code>track-reco</code> instead of <code>tracking</code>) your model shows up under <code>general</code>.</li></ul><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./../guide/tasks.html">Benchmark Tasks guide</a> — the tasks users train against when they publish a model</li><li><a href="./leaderboard.html">Leaderboard</a> — where shipped models go to battle</li></ul>`,18)]))}const u=t(i,[["render",o]]);export{g as __pageData,u as default};
